+        // Header magic "HdrS" at offset 0x202 (= 0x53726448 LE)
+        image[0x202] = 0x48; // 'H'
+        image[0x203] = 0x64; // 'd'
+        image[0x204] = 0x72; // 'r'
+        image[0x205] = 0x53; // 'S'
+
+        // Boot protocol version at offset 0x206: 2.15 (0x020F)
